import { Component, inject, signal, computed, effect, untracked, OnInit, ChangeDetectionStrategy } from '@angular/core';
import { CodeValueService, MPageService } from '@clinicaloffice/mpage-developer';
import { ConfigurationService } from '../../services/configuration.service';
import {
  OncSchedConfiguration,
  AppointmentTypeGroup,
  DEFAULT_REFRESH_INTERVAL_SECONDS,
  MIN_REFRESH_INTERVAL_SECONDS,
  MAX_REFRESH_INTERVAL_SECONDS
} from '../../models/schedule.model';
import { ApptTypeGroupEditorComponent } from './appt-type-group-editor/appt-type-group-editor';

@Component({
  selector: 'app-config',
  standalone: true,
  imports: [ApptTypeGroupEditorComponent],
  templateUrl: './config.html',
  styleUrl: './config.scss',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class ConfigComponent implements OnInit {
  private readonly codeValueService = inject(CodeValueService);
  private readonly configService = inject(ConfigurationService);
  private readonly mPage = inject(MPageService);

  readonly saving = signal(false);
  readonly apptTypesLoaded = signal(false);
  readonly positionsLoaded = signal(false);
  readonly encntrTypesLoaded = signal(false);
  readonly statusMessage = signal<string | null>(null);
  private statusTimer: ReturnType<typeof setTimeout> | null = null;

  readonly allApptTypes = signal<{ codeValue: number; display: string }[]>([]);
  readonly allPositions = signal<{ display: string }[]>([]);
  readonly allEncntrTypes = signal<{ codeValue: number; display: string }[]>([]);

  readonly groups = signal<AppointmentTypeGroup[]>([]);
  readonly selectedGroupId = signal<string | null>(null);
  readonly pendingDeleteId = signal<string | null>(null);

  readonly refreshIntervalSeconds = signal<number>(DEFAULT_REFRESH_INTERVAL_SECONDS);
  readonly minRefreshInterval = MIN_REFRESH_INTERVAL_SECONDS;
  readonly maxRefreshInterval = MAX_REFRESH_INTERVAL_SECONDS;
  readonly chartLinkEncntrTypeCd = signal<number>(0);

  private readonly configEffect = effect(() => {
    const config = this.configService.configuration();
    if (!config) return;
    untracked(() => {
      const next = (config.APPOINTMENT_TYPE_GROUPS ?? []).map(g => this.cloneGroup(g));
      this.groups.set(next);
      const ids = next.map(g => g.id);
      const currentSelection = this.selectedGroupId();
      if (currentSelection === null && ids.length > 0) {
        this.selectedGroupId.set(ids[0]);
      } else if (currentSelection && !ids.includes(currentSelection)) {
        this.selectedGroupId.set(ids[0] ?? null);
      }
      const stored = config.REFRESH_INTERVAL_SECONDS;
      this.refreshIntervalSeconds.set(
        typeof stored === 'number' && Number.isFinite(stored)
          ? stored
          : DEFAULT_REFRESH_INTERVAL_SECONDS
      );
      this.chartLinkEncntrTypeCd.set(config.CHART_LINK_ENCOUNTER_TYPE_CD ?? 0);
    });
  });

  readonly selectedGroup = computed<AppointmentTypeGroup | null>(() => {
    const id = this.selectedGroupId();
    if (!id) return null;
    return this.groups().find(g => g.id === id) ?? null;
  });

  readonly otherGroups = computed<AppointmentTypeGroup[]>(() => {
    const id = this.selectedGroupId();
    return this.groups().filter(g => g.id !== id);
  });

  readonly hasUnsavedChanges = computed(() => {
    const config = this.configService.configuration();
    const persisted = config?.APPOINTMENT_TYPE_GROUPS ?? [];
    if (!this.groupsEqual(persisted, this.groups())) return true;

    const storedInterval = typeof config?.REFRESH_INTERVAL_SECONDS === 'number'
      ? config.REFRESH_INTERVAL_SECONDS
      : DEFAULT_REFRESH_INTERVAL_SECONDS;
    if (storedInterval !== this.refreshIntervalSeconds()) return true;

    const storedEncntrTypeCd = config?.CHART_LINK_ENCOUNTER_TYPE_CD ?? 0;
    return storedEncntrTypeCd !== this.chartLinkEncntrTypeCd();
  });

  readonly hasGroupErrors = computed(() => {
    const all = this.groups();
    return all.some(g => {
      const label = g.label.trim();
      if (!label) return true;
      return all.some(other =>
        other.id !== g.id && other.label.trim().toLowerCase() === label.toLowerCase()
      );
    });
  });

  ngOnInit(): void {
    const existingAppt = this.codeValueService.getCodeSet(14230);
    if (existingAppt?.length) this.applyApptTypes(existingAppt);
    this.codeValueService.load(14230, 0, '', '', '', false, () => {
      this.applyApptTypes(this.codeValueService.getCodeSet(14230));
    });

    const existingPositions = this.codeValueService.getCodeSet(88);
    if (existingPositions?.length) this.applyPositions(existingPositions);
    this.codeValueService.load(88, 0, '', '', '', false, () => {
      this.applyPositions(this.codeValueService.getCodeSet(88));
    });

    const existingEncntr = this.codeValueService.getCodeSet(71);
    if (existingEncntr?.length) this.applyEncntrTypes(existingEncntr);
    this.codeValueService.load(71, 0, '', '', '', false, () => {
      this.applyEncntrTypes(this.codeValueService.getCodeSet(71));
    });
  }

  private applyApptTypes(codeValues: any[]): void {
    const values = codeValues.map(cv => ({ codeValue: cv.codeValue, display: cv.display }));
    values.sort((a, b) => a.display.localeCompare(b.display));
    this.allApptTypes.set(values);
    this.apptTypesLoaded.set(true);
  }

  private applyPositions(codeValues: any[]): void {
    const values = codeValues.map(cv => ({ display: cv.display as string }));
    values.sort((a, b) => a.display.localeCompare(b.display));
    this.allPositions.set(values);
    this.positionsLoaded.set(true);
  }

  private applyEncntrTypes(codeValues: any[]): void {
    const values = codeValues.map(cv => ({ codeValue: cv.codeValue, display: cv.display }));
    values.sort((a, b) => a.display.localeCompare(b.display));
    this.allEncntrTypes.set(values);
    this.encntrTypesLoaded.set(true);
  }

  selectGroup(id: string): void {
    this.selectedGroupId.set(id);
    this.pendingDeleteId.set(null);
  }

  newGroup(): void {
    const baseLabel = 'New group';
    const existing = new Set(this.groups().map(g => g.label.trim().toLowerCase()));
    let label = baseLabel;
    let n = 2;
    while (existing.has(label.toLowerCase())) {
      label = `${baseLabel} (${n})`;
      n += 1;
    }
    const id = this.makeId();
    const group: AppointmentTypeGroup = { id, label, positions: [], appointment_types: [] };
    this.groups.update(list => [...list, group]);
    this.selectedGroupId.set(id);
  }

  requestDelete(id: string): void {
    this.pendingDeleteId.set(id);
  }

  cancelDelete(): void {
    this.pendingDeleteId.set(null);
  }

  confirmDelete(id: string): void {
    this.groups.update(list => list.filter(g => g.id !== id));
    if (this.selectedGroupId() === id) {
      this.selectedGroupId.set(this.groups()[0]?.id ?? null);
    }
    this.pendingDeleteId.set(null);
  }

  onGroupChange(updated: AppointmentTypeGroup): void {
    this.groups.update(list => list.map(g => g.id === updated.id ? updated : g));
  }

  save(): void {
    if (this.hasGroupErrors()) {
      this.showStatus('Fix group errors before saving.');
      return;
    }
    this.saving.set(true);
    const config = this.configService.configuration();
    const updated: OncSchedConfiguration = {
      ...config ?? { UPDT_DT_TM: '', APPOINTMENT_TYPE_GROUPS: [] },
      APPOINTMENT_TYPE_GROUPS: this.groups().map(g => ({
        ...g,
        label: g.label.trim()
      })),
      REFRESH_INTERVAL_SECONDS: this.refreshIntervalSeconds(),
      CHART_LINK_ENCOUNTER_TYPE_CD: this.chartLinkEncntrTypeCd()
    };
    this.configService.saveConfiguration(updated);
    this.saving.set(false);
    this.showStatus('Configuration saved.');
  }

  discard(): void {
    const config = this.configService.configuration();
    this.groups.set([...(config?.APPOINTMENT_TYPE_GROUPS ?? []).map(g => this.cloneGroup(g))]);
    if (!this.groups().find(g => g.id === this.selectedGroupId())) {
      this.selectedGroupId.set(this.groups()[0]?.id ?? null);
    }
    const stored = config?.REFRESH_INTERVAL_SECONDS;
    this.refreshIntervalSeconds.set(
      typeof stored === 'number' && Number.isFinite(stored)
        ? stored
        : DEFAULT_REFRESH_INTERVAL_SECONDS
    );
    this.chartLinkEncntrTypeCd.set(config?.CHART_LINK_ENCOUNTER_TYPE_CD ?? 0);
    this.pendingDeleteId.set(null);
  }

  onRefreshIntervalInput(event: Event): void {
    const raw = (event.target as HTMLInputElement).value;
    const parsed = parseInt(raw, 10);
    if (!Number.isFinite(parsed)) return;
    this.refreshIntervalSeconds.set(this.clampInterval(parsed));
  }

  toggleAutoRefresh(): void {
    this.refreshIntervalSeconds.update(v =>
      v === 0 ? DEFAULT_REFRESH_INTERVAL_SECONDS : 0
    );
  }

  onChartLinkEncntrTypeChange(event: Event): void {
    const raw = (event.target as HTMLSelectElement).value;
    const parsed = parseInt(raw, 10);
    this.chartLinkEncntrTypeCd.set(Number.isFinite(parsed) ? parsed : 0);
  }

  private showStatus(message: string): void {
    if (this.statusTimer) clearTimeout(this.statusTimer);
    this.statusMessage.set(message);
    this.statusTimer = setTimeout(() => this.statusMessage.set(null), 4000);
  }

  private clampInterval(value: number): number {
    if (value <= 0) return 0;
    return Math.min(
      MAX_REFRESH_INTERVAL_SECONDS,
      Math.max(MIN_REFRESH_INTERVAL_SECONDS, Math.floor(value))
    );
  }

  private cloneGroup(g: AppointmentTypeGroup): AppointmentTypeGroup {
    return {
      id: g.id,
      label: g.label,
      positions: [...g.positions],
      appointment_types: [...g.appointment_types],
      lab_event_set_cd: g.lab_event_set_cd,
      lab_lookback_hours: g.lab_lookback_hours
    };
  }

  private groupsEqual(a: AppointmentTypeGroup[], b: AppointmentTypeGroup[]): boolean {
    if (a.length !== b.length) return false;
    const byId = new Map(b.map(g => [g.id, g]));
    for (const ag of a) {
      const bg = byId.get(ag.id);
      if (!bg) return false;
      if (ag.label !== bg.label) return false;
      if (!this.arraysEqual(ag.positions, bg.positions)) return false;
      if (!this.arraysEqual(ag.appointment_types.map(String), bg.appointment_types.map(String))) {
        return false;
      }
      if ((ag.lab_event_set_cd ?? 0) !== (bg.lab_event_set_cd ?? 0)) return false;
      if ((ag.lab_lookback_hours ?? 0) !== (bg.lab_lookback_hours ?? 0)) return false;
    }
    return true;
  }

  private arraysEqual(a: string[], b: string[]): boolean {
    if (a.length !== b.length) return false;
    const sa = [...a].sort();
    const sb = [...b].sort();
    return sa.every((v, i) => v === sb[i]);
  }

  private makeId(): string {
    if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
      return crypto.randomUUID();
    }
    return `grp-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
  }
}
