import {
  Component,
  Input,
  Output,
  EventEmitter,
  ChangeDetectionStrategy,
  signal,
  computed
} from '@angular/core';
import {
  AppointmentTypeGroup,
  DEFAULT_LAB_LOOKBACK_HOURS,
  MIN_LAB_LOOKBACK_HOURS,
  MAX_LAB_LOOKBACK_HOURS
} from '../../../models/schedule.model';

export interface PositionOption {
  display: string;
}

export interface ApptTypeOption {
  codeValue: number;
  display: string;
}

@Component({
  selector: 'app-appt-type-group-editor',
  standalone: true,
  templateUrl: './appt-type-group-editor.html',
  styleUrl: './appt-type-group-editor.scss',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class ApptTypeGroupEditorComponent {
  @Input({ required: true }) group!: AppointmentTypeGroup;
  @Input() otherGroups: AppointmentTypeGroup[] = [];
  @Input() allPositions: PositionOption[] = [];
  @Input() allApptTypes: ApptTypeOption[] = [];
  @Input() apptTypesLoaded = false;
  @Input() positionsLoaded = false;
  @Output() groupChange = new EventEmitter<AppointmentTypeGroup>();

  readonly positionSearch = signal('');
  readonly showSelectedPositionsOnly = signal(false);
  readonly apptTypeSearch = signal('');
  readonly showSelectedApptTypesOnly = signal(false);

  readonly filteredPositions = computed<PositionOption[]>(() => {
    const search = this.positionSearch().toLowerCase();
    const showSelected = this.showSelectedPositionsOnly();
    const selected = this.group?.positions ?? [];
    let list = this.allPositions;
    if (showSelected) list = list.filter(p => selected.includes(p.display));
    if (search) list = list.filter(p => p.display.toLowerCase().includes(search));
    return list;
  });

  readonly filteredApptTypes = computed<ApptTypeOption[]>(() => {
    const search = this.apptTypeSearch().toLowerCase();
    const showSelected = this.showSelectedApptTypesOnly();
    const selected = this.group?.appointment_types ?? [];
    let list = this.allApptTypes;
    if (showSelected) list = list.filter(a => selected.includes(a.codeValue));
    if (search) list = list.filter(a => a.display.toLowerCase().includes(search));
    return list;
  });

  labelError(): string | null {
    const label = this.group?.label?.trim() ?? '';
    if (!label) return 'Label is required.';
    const dup = this.otherGroups.some(g =>
      g.id !== this.group.id && g.label.trim().toLowerCase() === label.toLowerCase()
    );
    if (dup) return 'A group with this label already exists.';
    return null;
  }

  onLabelInput(event: Event): void {
    const value = (event.target as HTMLInputElement).value;
    this.groupChange.emit({ ...this.group, label: value });
  }

  isPositionSelected(position: string): boolean {
    return this.group?.positions.includes(position) ?? false;
  }

  positionsOtherOwners(position: string): string[] {
    return this.otherGroups
      .filter(g => g.positions.includes(position))
      .map(g => g.label);
  }

  togglePosition(position: string): void {
    const positions = new Set(this.group.positions);
    if (positions.has(position)) {
      positions.delete(position);
    } else {
      positions.add(position);
    }
    this.groupChange.emit({ ...this.group, positions: [...positions] });
  }

  checkAllFilteredPositions(): void {
    const filtered = this.filteredPositions().map(p => p.display);
    const set = new Set(this.group.positions);
    for (const display of filtered) set.add(display);
    this.groupChange.emit({ ...this.group, positions: [...set] });
  }

  uncheckAllFilteredPositions(): void {
    const filtered = new Set(this.filteredPositions().map(p => p.display));
    const next = this.group.positions.filter(p => !filtered.has(p));
    this.groupChange.emit({ ...this.group, positions: next });
  }

  toggleShowSelectedPositions(): void {
    this.showSelectedPositionsOnly.update(v => !v);
  }

  isApptTypeSelected(codeValue: number): boolean {
    return this.group?.appointment_types.includes(codeValue) ?? false;
  }

  toggleApptType(codeValue: number): void {
    const types = new Set(this.group.appointment_types);
    if (types.has(codeValue)) {
      types.delete(codeValue);
    } else {
      types.add(codeValue);
    }
    this.groupChange.emit({ ...this.group, appointment_types: [...types] });
  }

  checkAllFilteredApptTypes(): void {
    const filtered = this.filteredApptTypes().map(a => a.codeValue);
    const set = new Set(this.group.appointment_types);
    for (const code of filtered) set.add(code);
    this.groupChange.emit({ ...this.group, appointment_types: [...set] });
  }

  uncheckAllFilteredApptTypes(): void {
    const filtered = new Set(this.filteredApptTypes().map(a => a.codeValue));
    const next = this.group.appointment_types.filter(v => !filtered.has(v));
    this.groupChange.emit({ ...this.group, appointment_types: next });
  }

  toggleShowSelectedApptTypes(): void {
    this.showSelectedApptTypesOnly.update(v => !v);
  }

  readonly defaultLabLookback = DEFAULT_LAB_LOOKBACK_HOURS;
  readonly minLabLookback = MIN_LAB_LOOKBACK_HOURS;
  readonly maxLabLookback = MAX_LAB_LOOKBACK_HOURS;

  onLabEventSetInput(event: Event): void {
    const raw = (event.target as HTMLInputElement).value;
    const parsed = parseInt(raw, 10);
    this.groupChange.emit({
      ...this.group,
      lab_event_set_cd: Number.isFinite(parsed) && parsed > 0 ? parsed : undefined
    });
  }

  onLabLookbackInput(event: Event): void {
    const raw = (event.target as HTMLInputElement).value;
    const parsed = parseInt(raw, 10);
    if (!Number.isFinite(parsed) || parsed <= 0) {
      this.groupChange.emit({ ...this.group, lab_lookback_hours: undefined });
      return;
    }
    const clamped = Math.min(MAX_LAB_LOOKBACK_HOURS, Math.max(MIN_LAB_LOOKBACK_HOURS, parsed));
    this.groupChange.emit({ ...this.group, lab_lookback_hours: clamped });
  }

  onPositionSearchInput(event: Event): void {
    this.positionSearch.set((event.target as HTMLInputElement).value);
  }

  onApptTypeSearchInput(event: Event): void {
    this.apptTypeSearch.set((event.target as HTMLInputElement).value);
  }
}
